import{_ as s,o,c as t,a2 as a}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"Corpses — persistent enemy bodies (E2.4)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/corpses.md","filePath":"guide/corpses.md","lastUpdated":1781979562000}'),r={name:"guide/corpses.md"};function n(i,e,c,d,l,p){return o(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="corpses-—-persistent-enemy-bodies-e2-4" tabindex="-1">Corpses — persistent enemy bodies (E2.4) <a class="header-anchor" href="#corpses-—-persistent-enemy-bodies-e2-4" aria-label="Permalink to &quot;Corpses — persistent enemy bodies (E2.4)&quot;">​</a></h1><p>When an enemy dies it leaves a <strong>persistent, static 3D corpse</strong> in the world instead of vanishing. No physics engine is involved — a corpse is a toppled, inert reuse of the soldier mesh.</p><ul><li>Pure retention model: <code>src/game/corpses/corpseModel.ts</code></li><li>Session store (survives zone re-enter): <code>src/game/corpses/corpseStore.ts</code></li><li>Babylon spawner: <code>src/scenes/corpseManager.ts</code></li><li>Scene wiring: <code>src/scenes/forestScene.ts</code> (<code>reapDeadSoldiers</code>)</li></ul><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>live soldier ──[HP == 0, E2.3]──▶ reapDeadSoldiers()</span></span>
<span class="line"><span>   │                                  │</span></span>
<span class="line"><span>   │  hide live mesh (setEnabled false)│ CorpseManager.registerDeath()</span></span>
<span class="line"><span>   ▼                                  ▼</span></span>
<span class="line"><span>(removed from the fight)        record in CorpseStore  ──▶  spawn static corpse mesh</span></span>
<span class="line"><span>                                       │                         (toppled, inert)</span></span>
<span class="line"><span>                                  cap exceeded?</span></span>
<span class="line"><span>                                       ▼</span></span>
<span class="line"><span>                                evict oldest record ──▶ dispose its corpse mesh</span></span></code></pre></div><p>Each frame the forest scene calls <code>reapDeadSoldiers(soldiers, converted, corpses)</code>. For every soldier that newly reached the <code>dead</code> phase it:</p><ol><li>hides the live soldier mesh (<code>setEnabled(false)</code>) so it no longer reads as a combatant, and</li><li>hands its position + facing to <code>CorpseManager.registerDeath()</code>, which records the corpse and spawns a static &quot;downed&quot; mesh.</li></ol><p>The conversion is <strong>idempotent per soldier</strong> (tracked in a <code>Set</code>), so a soldier is never turned into two corpses.</p><h2 id="corpse-mesh" tabindex="-1">Corpse mesh <a class="header-anchor" href="#corpse-mesh" aria-label="Permalink to &quot;Corpse mesh&quot;">​</a></h2><p>A corpse is a capsule (radius 0.35 m) rotated 90° onto its side, resting on the ground, keeping the yaw the enemy faced when it fell. The soldier GLB (<code>/models/empire-soldier.glb</code>) is mounted as a child best-effort; if the fetch fails (or in headless tests) the toppled capsule remains as the visible fallback.</p><p>Corpses are <strong>inert</strong>: <code>isPickable = false</code> and <code>checkCollisions = false</code>. They are not registered with the fixed-step loop, so they never act, never tick, and the melee hit sweep already filters them out (<code>soldiers.filter(s =&gt; !s.isDead())</code>).</p><h2 id="retention-cleanup-policy-the-cap" tabindex="-1">Retention / cleanup policy (the cap) <a class="header-anchor" href="#retention-cleanup-policy-the-cap" aria-label="Permalink to &quot;Retention / cleanup policy (the cap)&quot;">​</a></h2><p>Corpses are capped so the mesh count — and therefore the frame budget — can never grow unbounded. The policy is <strong>FIFO across the session</strong>:</p><ul><li>One session-wide budget of <code>DEFAULT_CORPSE_CAP = 32</code> corpses (all zones share it). 32 low-poly soldier bodies (~2.8k tris each) stays comfortably within the frame budget while still reading as a real battlefield.</li><li>When a new corpse would exceed the cap, the <strong>oldest</strong> corpse is evicted: its record is dropped and its mesh disposed.</li><li>The cap is configurable (<code>new CorpseStore(cap)</code>), e.g. <code>0</code> for a no-corpses configuration.</li></ul><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scope</th><th>Behaviour</th></tr></thead><tbody><tr><td>Within a zone visit</td><td>Corpses stay until the cap evicts them.</td></tr><tr><td>Zone re-enter (same session)</td><td><strong>Persists.</strong> The store lives at module scope, so a rebuilt scene re-spawns the corpses recorded for that zone via <code>CorpseManager</code>&#39;s constructor.</td></tr><tr><td>Page reload</td><td><strong>Not persisted (out of scope).</strong> Corpses are deliberately not written to the IndexedDB save (FLO-296) — full reload persistence would mean a save-schema migration for a cosmetic, capped, in-session feature. The store resets to empty on reload by design.</td></tr></tbody></table><p>Corpses are keyed by <code>zoneId</code>, so a corpse only re-spawns in the zone where the enemy died — entering a different zone shows that zone&#39;s own corpses only.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li><code>src/game/corpses/corpseModel.test.ts</code> — cap / FIFO eviction, immutability.</li><li><code>src/game/corpses/corpseStore.test.ts</code> — record ids, persistence, cap, reset.</li><li><code>src/scenes/corpseManager.test.ts</code> — mesh spawn, inert flags, eviction disposal, zone-scoped re-spawn (NullEngine).</li><li><code>src/scenes/forestScene.test.ts</code> — <code>reapDeadSoldiers</code> live→corpse transition and boot-time re-spawn.</li></ul>`,19)])])}const u=s(r,[["render",n]]);export{m as __pageData,u as default};
